    16→// Message represents the message object in assistant events
    17→type Message struct {
    18→	Model      string               `json:"model"`
    19→	ID         string               `json:"id"`
    20→	Type       string               `json:"type"`
    21→	Role       string               `json:"role"`
    22→	Content    []types.ContentBlock `json:"content"`
    23→	StopReason *string              `json:"stop_reason"`
    24→	Usage      *types.Usage         `json:"usage"`
    25→}
    26→
    27→// Event represents an assistant message event
    28→type Event struct {
    29→	types.BaseEvent
