    34→var markdownRenderer *render.MarkdownRenderer
    35→
    36→func getMarkdownRenderer() *render.MarkdownRenderer {
    37→	if markdownRenderer == nil {
    38→		width := 80
    39→		if w, _, err := term.GetSize(int(os.Stdout.Fd())); err == nil && w > 0 {
    40→			width = w
    41→		}
    42→		markdownRenderer = render.NewMarkdownRenderer(config.NoColor, width)
    43→	}
    44→	return markdownRenderer
    45→}
