    47→// Render outputs the assistant event to the terminal
    48→// inTextBlock and inToolUseBlock indicate whether we were streaming these block types
    49→func Render(event Event, inTextBlock, inToolUseBlock bool) {
    50→	if event.Error != "" {
    51→		fmt.Println(style.Error.Bold(true).Render(fmt.Sprintf("%sError", style.Bullet)))
    52→		fmt.Printf("%s%s\n", style.OutputPrefix, style.Error.Render(event.Error))
    53→	}
    54→
    55→	for _, block := range event.Message.Content {
    56→		switch block.Type {
    57→		case "text":
    58→			// Only render if we weren't streaming (text would already be shown)
    59→			if !inTextBlock {
    60→				// Use markdown renderer for non-streamed text
    61→				rendered := getMarkdownRenderer().Render(block.Text)
    62→				fmt.Print(rendered)
    63→				if !strings.HasSuffix(rendered, "\n") {
    64→					fmt.Println()
    65→				}
    66→			}
    67→		case "tool_use":
    68→			// Only render if we weren't streaming
    69→			if !inToolUseBlock {
    70→				tools.RenderToolUse(block)
    71→			}
    72→		}
    73→	}
    74→}
