    56→// Render outputs the user event to the terminal
    57→func Render(event Event) {
    58→	for _, content := range event.Message.Content {
    59→		if content.IsError {
    60→			// Show error with output prefix
    61→			errMsg := terminal.Truncate(content.Content, 200)
    62→			fmt.Printf("%s%s\n", style.OutputPrefix, style.Error.Render(errMsg))
    63→		} else if content.Content != "" {
    64→			lines := strings.Split(content.Content, "\n")
    65→			lineCount := len(lines)
    66→
    67→			if config.Verbose {
    68→				// Show full content with syntax highlighting
    69→				highlighted := highlightContent(content.Content)
    70→				resultLines := strings.Split(highlighted, "\n")
    71→				for i, line := range resultLines {
    72→					if i == 0 {
    73→						fmt.Printf("%s%s\n", style.OutputPrefix, line)
    74→					} else {
    75→						fmt.Printf("%s%s\n", style.OutputContinue, line)
    76→					}
    77→				}
    78→			} else {
    79→				// Show summary in non-verbose mode
    80→				summary := fmt.Sprintf("Read %d lines", lineCount)
    81→				fmt.Printf("%s%s\n", style.OutputPrefix, style.Muted.Render(summary))
    82→			}
    83→		}
    84→	}
    85→}
