    87→// highlightContent applies syntax highlighting based on context
    88→func highlightContent(content string) string {
    89→	cr := getCodeRenderer()
    90→
    91→	// Try to detect language from the last tool's file path
    92→	if lastToolPath != "" {
    93→		lang := render.DetectLanguageFromPath(lastToolPath)
    94→		if lang != "" {
    95→			return cr.Highlight(content, lang)
    96→		}
    97→	}
    98→
    99→	// Try to auto-detect from content
   100→	return cr.HighlightFile(content, lastToolPath)
   101→}
