    17→// EventData represents the nested event in stream_event
    18→type EventData struct {
    19→	Type         string          `json:"type"`
    20→	Index        int             `json:"index"`
    21→	Message      json.RawMessage `json:"message,omitempty"`
    22→	ContentBlock json.RawMessage `json:"content_block,omitempty"`
    23→	Delta        json.RawMessage `json:"delta,omitempty"`
    24→	Usage        *types.Usage    `json:"usage,omitempty"`
    25→}
    26→
    27→// Event represents a streaming event
    28→type Event struct {
    29→	types.BaseEvent
    30→	Event EventData `json:"event"`
    31→}
    32→
    33→// TextDelta represents a text delta in streaming
    34→type TextDelta struct {
    35→	Type string `json:"type"`
    36→	Text string `json:"text"`
    37→}
    38→
    39→// InputJSONDelta represents a JSON input delta in streaming
    40→type InputJSONDelta struct {
    41→	Type        string `json:"type"`
    42→	PartialJSON string `json:"partial_json"`
    43→}
    44→
    45→// MessageDelta represents a message delta
    46→type MessageDelta struct {
    47→	StopReason   string `json:"stop_reason"`
    48→	StopSequence string `json:"stop_sequence"`
    49→}
    50→
    51→// Renderer handles rendering stream events and tracks streaming state
    52→type Renderer struct {
    53→	CurrentBlockIndex int
    54→	CurrentBlockType  string
    55→	InTextBlock       bool
    56→	InToolUseBlock    bool
    57→	toolName          string
    58→	toolInput         strings.Builder
    59→	textBuffer        strings.Builder
    60→	markdownRenderer  *render.MarkdownRenderer
    61→	width             int
    62→}
    63→
    64→// NewRenderer creates a new stream Renderer
    65→func NewRenderer() *Renderer {
    66→	// Get terminal width for markdown wrapping
    67→	width := 80
    68→	if w, _, err := term.GetSize(int(os.Stdout.Fd())); err == nil && w > 0 {
    69→		width = w
    70→	}
    71→
    72→	return &Renderer{
    73→		CurrentBlockIndex: -1,
    74→		markdownRenderer:  render.NewMarkdownRenderer(config.NoColor, width),
    75→		width:             width,
    76→	}
    77→}
    78→
    79→// Render outputs the stream event to the terminal
    80→func (r *Renderer) Render(event Event) {
    81→	switch event.Event.Type {
    82→	case "message_start":
    83→		// Message starting, nothing to render
    84→	case "content_block_start":
    85→		r.CurrentBlockIndex = event.Event.Index
    86→		if len(event.Event.ContentBlock) > 0 {
    87→			var block types.ContentBlock
    88→			if err := json.Unmarshal(event.Event.ContentBlock, &block); err == nil {
    89→				r.CurrentBlockType = block.Type
    90→				if block.Type == "text" {
    91→					r.InTextBlock = true
    92→					r.textBuffer.Reset()
    93→				} else if block.Type == "tool_use" {
    94→					r.InToolUseBlock = true
    95→					r.toolName = block.Name
    96→					r.toolInput.Reset()
    97→				}
    98→			}
    99→		}
   100→	case "content_block_delta":
   101→		if len(event.Event.Delta) > 0 {
   102→			// Try text delta first
   103→			var textDelta TextDelta
   104→			if err := json.Unmarshal(event.Event.Delta, &textDelta); err == nil && textDelta.Type == "text_delta" {
   105→				// Buffer text for markdown rendering when block completes
   106→				r.textBuffer.WriteString(textDelta.Text)
   107→				return
   108→			}
   109→			// Try input JSON delta
   110→			var jsonDelta InputJSONDelta
   111→			if err := json.Unmarshal(event.Event.Delta, &jsonDelta); err == nil && jsonDelta.Type == "input_json_delta" {
   112→				r.toolInput.WriteString(jsonDelta.PartialJSON)
   113→			}
   114→		}
   115→	case "content_block_stop":
   116→		if r.InTextBlock && event.Event.Index == r.CurrentBlockIndex {
   117→			// Render buffered text with markdown
   118→			text := r.textBuffer.String()
   119→			if text != "" {
   120→				rendered := r.markdownRenderer.Render(text)
   121→				fmt.Print(rendered)
   122→			}
   123→		} else if r.InToolUseBlock && event.Event.Index == r.CurrentBlockIndex {
   124→			// Parse and display the accumulated tool input with full header
   125→			var input map[string]interface{}
   126→			toolInputStr := r.toolInput.String()
   127→			if err := json.Unmarshal([]byte(toolInputStr), &input); err == nil {
   128→				tools.RenderToolHeader(r.toolName, input)
   129→			} else {
   130→				// Fallback if JSON parse fails
   131→				fmt.Println(style.ToolHeader.Render(fmt.Sprintf("%s%s()", style.Bullet, r.toolName)))
   132→			}
   133→		}
   134→	case "message_delta":
   135→		// Contains stop_reason, nothing to render
   136→	case "message_stop":
   137→		// Message complete
   138→		// Note: Don't reset InTextBlock/InToolUseBlock here - they persist
   139→		// until after the assistant event is processed to prevent duplicate rendering
   140→		r.CurrentBlockIndex = -1
   141→	}
   142→}
   143→
   144→// GetBufferedText returns the accumulated text buffer content
   145→func (r *Renderer) GetBufferedText() string {
   146→	return r.textBuffer.String()
   147→}
   148→
   149→// ResetBlockState resets the block tracking state after an assistant event
   150→func (r *Renderer) ResetBlockState() {
   151→	r.InTextBlock = false
   152→	r.InToolUseBlock = false
   153→}
