     9→// MarkdownRenderer wraps glamour for markdown rendering
    10→type MarkdownRenderer struct {
    11→	renderer *glamour.TermRenderer
    12→	noColor  bool
    13→}
    14→
    15→// NewMarkdownRenderer creates a new markdown renderer
    16→func NewMarkdownRenderer(noColor bool, width int) *MarkdownRenderer {
    17→	var renderer *glamour.TermRenderer
    18→	var err error
    19→
    20→	if noColor {
    21→		renderer, err = glamour.NewTermRenderer(
    22→			glamour.WithStylePath("notty"),
    23→			glamour.WithWordWrap(width),
    24→		)
    25→	} else {
    26→		renderer, err = glamour.NewTermRenderer(
    27→			glamour.WithAutoStyle(),
    28→			glamour.WithWordWrap(width),
    29→		)
    30→	}
    31→
    32→	if err != nil {
    33→		// Fall back to no rendering on error
    34→		return &MarkdownRenderer{noColor: noColor}
    35→	}
    36→
    37→	return &MarkdownRenderer{
    38→		renderer: renderer,
    39→		noColor:  noColor,
    40→	}
    41→}
    42→
    43→// Render renders markdown content to styled terminal output
    44→func (m *MarkdownRenderer) Render(content string) string {
    45→	if m.renderer == nil {
    46→		return content
    47→	}
    48→
    49→	rendered, err := m.renderer.Render(content)
    50→	if err != nil {
    51→		return content
    52→	}
    53→
    54→	// Glamour adds trailing newlines, trim to single newline
    55→	return strings.TrimRight(rendered, "\n") + "\n"
    56→}
