    13→// RenderToolUse renders a tool use block header and input
    14→func RenderToolUse(block types.ContentBlock) {
    15→	if len(block.Input) > 0 {
    16→		var input map[string]interface{}
    17→		if err := json.Unmarshal(block.Input, &input); err == nil {
    18→			RenderToolHeader(block.Name, input)
    19→			return
    20→		}
    21→	}
    22→	// Fallback if no input or parse error
    23→	fmt.Println(style.ToolHeader.Render(fmt.Sprintf("%s%s()", style.Bullet, block.Name)))
    24→	user.SetToolContext(block.Name, "")
    25→}
