    27→// RenderToolHeader renders the tool header in Claude Code format: ● ToolName(args)
    28→func RenderToolHeader(toolName string, input map[string]interface{}) {
    29→	var args string
    30→	var filePath string
    31→
    32→	switch toolName {
    33→	case "Bash":
    34→		if cmd, ok := input["command"].(string); ok {
    35→			args = cmd
    36→		}
    37→	case "Read":
    38→		if path, ok := input["file_path"].(string); ok {
    39→			args = path
    40→			filePath = path
    41→		}
    42→	case "Write":
    43→		if path, ok := input["file_path"].(string); ok {
    44→			args = path
    45→			filePath = path
    46→		}
    47→	case "Edit":
    48→		if path, ok := input["file_path"].(string); ok {
    49→			args = path
    50→			filePath = path
    51→		}
    52→	case "Glob":
    53→		if pattern, ok := input["pattern"].(string); ok {
    54→			args = pattern
    55→		}
    56→	case "Grep":
    57→		if pattern, ok := input["pattern"].(string); ok {
    58→			args = pattern
    59→		}
    60→	case "Task":
    61→		if desc, ok := input["description"].(string); ok {
    62→			args = desc
    63→		}
    64→	default:
    65→		// For unknown tools, show compact JSON
    66→		if config.Verbose {
    67→			if data, err := json.Marshal(input); err == nil {
    68→				args = string(data)
    69→				if len(args) > 100 {
    70→					args = args[:100] + "..."
    71→				}
    72→			}
    73→		}
    74→	}
    75→
    76→	// Truncate long args
    77→	if len(args) > 80 {
    78→		args = args[:77] + "..."
    79→	}
    80→
    81→	header := fmt.Sprintf("%s%s(%s)", style.Bullet, toolName, args)
    82→	fmt.Println(style.ToolHeader.Render(header))
    83→
    84→	// Set context for syntax highlighting of tool results
    85→	user.SetToolContext(toolName, filePath)
    86→}
